export async function POST() {
  try {
    const supabase = await createClient()
    
    const batchSize = 50
    let inserted = 0
    let skipped = 0
    
    for (let i = 0; i < DRIVERS_DATA.length; i += batchSize) {
      const batch = DRIVERS_DATA.slice(i, i + batchSize)
      
      const { error, data } = await supabase
        .from('drivers')
        .insert(batch)
        .select()
      
      if (error) {
        if (error.code === '23505') {
          skipped += batch.length
        } else {
          console.error('Error inserting batch:', error)
        }
      } else {
        inserted += data?.length || 0
      }
    }
    
    return NextResponse.json({
      success: true,
      message: `Sync completed. Inserted: ${inserted}, Skipped (duplicates): ${skipped}, Total: ${DRIVERS_DATA.length}`
    })
  } catch (error) {
    console.error('Sync error:', error)
    return NextResponse.json(
      { error: 'Failed to sync drivers' },
      { status: 500 }
    )
  }
}
